from typing import List

class Solution:
    def maximizeTheProfit(self, n: int, offers: List[List[int]]) -> int:
        # Group offers by their left endpoint so when dp[l] is finalized,
        # we can deterministically relax dp[r+1].
        grouped = [[] for _ in range(n)]
        for s, e, g in offers:
            grouped[s].append((e, g))

        dp = [0] * (n + 1)  # dp[i] = best profit using houses strictly before i
        for i in range(n):
            # Carry transition: best for prefix i+1 is at least best for prefix i
            if dp[i + 1] < dp[i]:
                dp[i + 1] = dp[i]

            # Try all offers that start at i. If we take (i..e), we jump to e+1.
            base = dp[i]
            if grouped[i]:
                for e, g in grouped[i]:
                    nxt = e + 1
                    val = base + g
                    if dp[nxt] < val:
                        dp[nxt] = val

        return dp[n]
