from typing import List
from collections import defaultdict

class Solution:
    def maximizeTheProfit(self, n: int, offers: List[List[int]]) -> int:
        # dp[i] = max gold we can earn using only houses [0..i-1]
        # answer will be dp[n]
        dp = [0] * (n + 1)

        # Group offers by their right endpoint: (l, r, g) contributes from dp[l] to dp[r+1]
        by_end = defaultdict(list)
        for s, e, g in offers:
            by_end[e].append((s, g))

        for i in range(n):
            # prefix carry: best up to i carries to i+1
            if dp[i + 1] < dp[i]:
                dp[i + 1] = dp[i]

            # apply all offers that end at i- we update dp[i+1] from dp[s]
            if i in by_end:
                base = dp  # local alias
                for s, g in by_end[i]:
                    cand = base[s] + g
                    if dp[i + 1] < cand:
                        dp[i + 1] = cand

        return dp[n]
