from typing import List

class Solution:
    def maximizeTheProfit(self, n: int, offers: List[List[int]]) -> int:
        # dp[i] = max profit using only houses in [0..i-1] (prefix of length i)
        # Answer is dp[n]
        dp = [0] * (n + 1)

        # Group offers by their start, since when we are at dp[left],
        # taking an offer deterministically transitions to dp[right+1]
        by_start = [[] for _ in range(n)]
        for s, e, g in offers:
            by_start[s].append((e, g))

        for left in range(n):
            # Carry transition: dp is non-decreasing across prefix lengths
            if dp[left + 1] < dp[left]:
                dp[left + 1] = dp[left]

            base = dp[left]
            if not by_start[left]:
                continue

            for e, g in by_start[left]:
                nxt = e + 1
                cand = base + g
                if dp[nxt] < cand:
                    dp[nxt] = cand

        # final carry (in case updates land earlier but not at n)
        for i in range(n):
            if dp[i + 1] < dp[i]:
                dp[i + 1] = dp[i]
        return dp[n]
