from typing import List
import bisect

class Solution:
    def maximizeTheProfit(self, n: int, offers: List[List[int]]) -> int:
        # Coordinate compression on all relevant boundaries:
        # DP boundaries correspond to "next position to consider" after skipping.
        # For an offer [l, r], it always transitions from boundary at l to boundary at r+1.
        coords = {0, n}
        for l, r, _ in offers:
            coords.add(l)
            coords.add(r + 1)

        sorted_coords = sorted(coords)
        idx = {x: i for i, x in enumerate(sorted_coords)}
        m = len(sorted_coords)

        # Group offers by their left boundary coordinate
        grouped = [[] for _ in range(m)]
        for l, r, g in offers:
            grouped[idx[l]].append((idx[r + 1], g))

        # dp[i] = max profit achievable when the next undecided position is sorted_coords[i]
        dp = [0] * m

        for i in range(m - 1):
            # Prefix-max carry (skip transition)
            if dp[i + 1] < dp[i]:
                dp[i + 1] = dp[i]

            # Take any offer whose start matches this boundary
            base = dp[i]
            if base == 0 and not grouped[i]:
                continue
            for j, g in grouped[i]:
                val = base + g
                if dp[j] < val:
                    dp[j] = val

        # One more carry to ensure non-decreasing dp across remaining gaps
        for i in range(m - 1):
            if dp[i + 1] < dp[i]:
                dp[i + 1] = dp[i]

        return dp[idx[n]]
